CREATE OR REPLACE FUNCTION sync_module_study_event_def_to_study_event_def() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO study_event_definition ( study_event_definition_id, study_id, name, description, repeating, type, category, oc_oid, ordinal, date_created, date_updated, owner_id, update_id, status_id ) VALUES ( NEW.study_event_definition_id, NEW.study_id, NEW.name, NEW.description, NEW.repeating, NEW.type, NEW.category, NEW.oc_oid, NEW.ordinal, NEW.date_created, NEW.date_updated, NEW.owner_id, NEW.update_id, NEW.status_id ) ON CONFLICT (study_event_definition_id) DO UPDATE SET study_id = EXCLUDED.study_id, name = EXCLUDED.name, description = EXCLUDED.description, repeating = EXCLUDED.repeating, type = EXCLUDED.type, category = EXCLUDED.category, oc_oid = EXCLUDED.oc_oid, ordinal = EXCLUDED.ordinal, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, owner_id = EXCLUDED.owner_id, update_id = EXCLUDED.update_id, status_id = EXCLUDED.status_id; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE study_event_definition SET study_id = NEW.study_id, name = NEW.name, description = NEW.description, repeating = NEW.repeating, type = NEW.type, category = NEW.category, oc_oid = NEW.oc_oid, ordinal = NEW.ordinal, date_created = NEW.date_created, date_updated = NEW.date_updated, owner_id = NEW.owner_id, update_id = NEW.update_id, status_id = NEW.status_id WHERE study_event_definition_id = OLD.study_event_definition_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM study_event_definition WHERE study_event_definition_id = OLD.study_event_definition_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
