DROP TRIGGER IF EXISTS trg_sync_module_study_event_def ON module_study_event_definition; CREATE TRIGGER trg_sync_module_study_event_def AFTER INSERT OR UPDATE OR DELETE ON module_study_event_definition FOR EACH ROW EXECUTE FUNCTION sync_module_study_event_def_to_study_event_def();
DROP TRIGGER IF EXISTS trg_sync_study_event_def_to_module ON study_event_definition; CREATE TRIGGER trg_sync_study_event_def_to_module AFTER INSERT OR UPDATE OR DELETE ON study_event_definition FOR EACH ROW EXECUTE FUNCTION sync_study_event_def_to_module_study_event_def();

