d; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_sync_module_study_event ON module_study_event; CREATE TRIGGER trg_sync_module_study_event AFTER INSERT OR UPDATE OR DELETE ON module_study_event FOR EACH ROW EXECUTE FUNCTION sync_module_study_event_to_study_event();
