tions = NEW.annotations, date_completed = NEW.date_completed, validator_id = NEW.validator_id, date_validate = NEW.date_validate, date_validate_completed = NEW.date_validate_completed, validator_annotations = NEW.validator_annotations, date_created = NEW.date_created, date_updated = NEW.date_updated, owner_id = NEW.owner_id, update_id = NEW.update_id, electronic_signature_status = NEW.electronic_signature_status, sdv_status = NEW.sdv_status, old_status_id = NEW.old_status_id, sdv_update_id = NEW.sdv_update_id WHERE event_crf_id = OLD.event_crf_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM event_crf WHERE event_crf_id = OLD.event_crf_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
